THE CLAIM:
{
 "title": "Per-country registrations delay sales, cutting Year-1 reach",
 "narrative": "The model assumes the venture can reach 45% of its serviceable market in Year 1. But each country needs registrations done before the first legal sale, and Germany's WEEE setup alone takes 2 to 4 months. Because these steps run one after another, several countries stay unreachable for part of the year, pushing Year-1 reach below the low edge and dropping Switzerland out entirely.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Each country needs registrations done before any legal sale.",
   "refs": [
    "digest:serviceable-benchmark#c10",
    "ledger:geo.CH"
   ]
  },
  {
   "step": "propagation",
   "text": "Registrations run in sequence, so reachable countries grow slowly across 12 months.",
   "refs": [
    "ledger:serviceableFactor",
    "digest:serviceable-benchmark#c12",
    "profile:Stage"
   ]
  },
  {
   "step": "model-impact",
   "text": "Year-1 reach drops below the band edge and Switzerland falls out.",
   "refs": [
    "ledger:serviceableFactor",
    "ledger:geo.CH"
   ]
  }
 ],
 "falsifier": "A counsel-built timeline showing all CE-7 registrations, including Swiss setup, can finish in parallel within 90 days before launch.",
 "category": "fact",
 "evidence": [
  {
   "title": "Wie lange dauert die Registrierung? (stiftung EAR WEEE)",
   "sourceType": "industry-report",
   "publisher": "Elektrogesetz.de",
   "date": "2019-09-17",
   "excerpt": "Von der Beantragung bis zur Erteilung einer WEEE-Registrierung durch die Stiftung EAR, vergehen weiterhin „mehrere Monate“... etwa 8 bis 10 Wochen... First in, first out; keine beschleunigte Bearbeitung.",
   "url": "https://www.elektrogesetz.de/wie-lange-dauert-die-registrierung/",
   "attached": true
  },
  {
   "title": "EPR-Nummer in Deutschland beantragen: Schritt fuer Schritt",
   "sourceType": "industry-report",
   "publisher": "Koorvi",
   "date": "2026-06-19",
   "excerpt": "In Deutschland sind es in Wahrheit drei verschiedene Register, drei Nummern und zwei Behoerden... bevor dein erstes Produkt in Deutschland in Verkehr geht.",
   "url": "https://www.koorvi.com/de/blog/epr-nummer-beantragen-deutschland",
   "attached": true
  },
  {
   "title": "WEEE Schweiz / SENS eRecycling",
   "sourceType": "industry-report",
   "publisher": "take-e-way / Stiftung SENS",
   "date": "2021-06-29",
   "excerpt": "Die Stiftung SENS organisiert in der Schweiz die Entsorgung von elektronischen Haushaltsgeräten — separate importer/recycling regime for non-EU Switzerland.",
   "url": "https://www.take-e-way.de/news/weee-schweiz-oeffentliche-liste-der-nicht-systemteilnehmer/",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "geo.CH",
  "label": "Switzerland",
  "kind": "estimated",
  "value": 0.08,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": "geography",
  "dimensionValue": "CH",
  "sensitivityRange": {
   "low": 0.07,
   "high": 0.13
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down capacity apportionment",
   "expression": "CH colo 274 MW ÷ CE-7 colo 3,451 MW (Statista 2025) = 0.079 → 0.08 (normalized)",
   "crossCheck": "Installed-base method (Mordor 850.6 MW incl. self-operated) → ~0.13 — Swiss market is self-operation-heavy"
  },
  "provenance": {
   "rationale": "Large self-operated share (CBRE Suisse: 340 MW commercial only) makes scope choice decisive → inferred, wide band."
  },
  "evidence": [
   {
    "title": "Europe colocation data center IT power supply by country, 2024–2031",
    "sourceType": "industry-report",
    "publisher": "Statista",
    "date": "2026-02-06",
    "excerpt": "Switzerland 274 MW of colocation and scale-colocation IT power in 2025.",
    "attached": true
   },
   {
    "title": "CBRE Suisse — Swiss data-center market capacity",
    "sourceType": "analyst-estimate",
    "publisher": "CBRE Suisse",
    "date": "2026",
    "excerpt": "Commercial capacity (excluding self-operated infrastructure) is 340 MW across 121 sites; ~61% (209 MW) concentrated in the Zurich region.",
    "attached": true
   }
  ]
 },
 {
  "id": "serviceableFactor",
  "label": "Serviceable share of TAM",
  "kind": "assumption",
  "value": 0.55,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "needs-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.45,
   "high": 0.65
  },
  "funnelActive": true,
  "derivation": {
   "method": "Reachability assumption",
   "expression": "No public SAM/TAM benchmark for B2B hardware exists; EU cert stack (EN 50600, ecodesign 2019/424, CE/TÜV) justifies < 1.0 but doesn't quantify 0.55"
  },
  "provenance": {
   "rationale": "Assumption leaf — channel + regulatory reach; EU certification barriers documented qualitatively only.",
   "promotionPath": "Bottom-up channel-coverage model (named accounts × reachable share) → sourced serviceable %."
  },
  "evidence": [
   {
    "title": "EU ecodesign requirements for servers and data storage (2019/424)",
    "sourceType": "industry-report",
    "publisher": "EUR-Lex",
    "date": "2019",
    "excerpt": "EU ecodesign and certification requirements gate which demand is regulatory-clear for a new entrant — the qualitative basis of the serviceable haircut.",
    "attached": true
   }
  ]
 }
]

